parameters.jsCode:
const expectedManagers = [
  'Breanna',
  'Amy',
  'Debbie',
  'Dede',
  'Shelbie/Chris',
  'Ashlie'
];

const submitted = $input.all().map(i => i.json.manager_name).filter(Boolean);
const missing = expectedManagers.filter(name => !submitted.includes(name));
const week_reference = $('Build Week Reference').item.json.week_reference;
const webhook_url = $('Build Week Reference').item.json.webhook_url;

return [{
  json: {
    week_reference,
    webhook_url,
    expectedManagers,
    submitted,
    missing,
    total_expected: expectedManagers.length,
    total_submitted: submitted.length
  }
}];

const {
  missing,
  submitted,
  total_submitted,
  total_expected,
  week_reference,
  webhook_url
} = $json;

const submittedBlock = submitted.length
  ? submitted.map(name => `• ${name}`).join('<br>')
  : 'None';

const missingBlock = missing.length
  ? missing.map(name => `• ${name}`).join('<br>')
  : 'None';

const praiseText = submitted.length
  ? `<b>Nice work to those already submitted.</b> Thank you for getting your weekly report in on time.`
  : `<b>No reports have been submitted yet.</b>`;

return [{
  json: {
    webhook_url,
    payload: {
      cardsV2: [
        {
          cardId: 'weekly-report-status',
          card: {
            header: {
              title: 'Weekly Reporting Status',
              subtitle: `Week of ${week_reference} • Submitted: ${total_submitted} / ${total_expected}`,
              imageUrl: 'https://blaze-assets.sfo3.cdn.digitaloceanspaces.com/blaze-logo-mark.png',
              imageType: 'CIRCLE'
            },
            sections: [
              {
                widgets: [
                  {
                    textParagraph: {
                      text: praiseText
                    }
                  },
                  {
                    textParagraph: {
                      text: `<b>Submitted</b><br><br>${submittedBlock}`
                    }
                  },
                  {
                    textParagraph: {
                      text: `<b>Still Missing</b><br><br>${missingBlock}`
                    }
                  },
                  {
                    textParagraph: {
                      text: `Weekly reports are due every Monday by <b>10:00 AM</b>.`
                    }
                  },
                  {
                    buttonList: {
                      buttons: [
                        {
                          text: 'Open Weekly Report',
                          onClick: {
                            openLink: {
                              url: 'https://blzres.com/weekly-reporting/'
                            }
                          }
                        }
                      ]
                    }
                  }
                ]
              }
            ]
          }
        }
      ]
    }
  }
}];

